192	          (in comment name of property that controls indentation):
193	        </p>
194	        <div class="wrapper"><pre class="prettyprint"><code class="language-java">
195	class Example2 {
196	    String field = "example";                  // basicOffset
197	    int[] values = {                           // basicOffset
198	        10,
199	        20,
200	        30
201	    };
202	
203	    void processValues() throws Exception {
204	        handleValue("Test String", 42);          // basicOffset
205	    }
206	
207	    void handleValue(String aFooString,
208	                     int aFooInt) {
209	
210	        boolean cond1,cond2,cond3,cond4,cond5,cond6;
211	        cond1=cond2=cond3=cond4=cond5=cond6=false;
212	
213	        if (cond1
214	            || cond2) {
215	            field = field.toUpperCase()
216	                .concat(" TASK");
217	        }
218	
219	        if ((cond1 &amp;&amp; cond2)
220	                || (cond3 &amp;&amp; cond4)           // ok, lineWrappingIndentation
221	                || !(cond5 &amp;&amp; cond6)) {       // ok, lineWrappingIndentation
222	            field.toUpperCase()
223	                 .concat(" TASK")             // ok, lineWrappingIndentation
224	                 .chars().forEach(c -&gt; {      // ok, lineWrappingIndentation
