281	                || !(cond5 &amp;&amp; cond6)) {    // violation, "incorrect indentation"
282	            field.toUpperCase()
283	                 .concat(" TASK")           // violation, "incorrect indentation"
284	                 .chars().forEach(c -&gt; {    // violation, "incorrect indentation"
285	                     System.out.println((char) c);
286	                 });
287	        }
288	    }
