332	                     System.out.println((char) c);
333	                 });
334	        }
335	    }
336	
337	    void demonstrateSwitch() throws Exception {
338	        switch (field) {
339	            case "EXAMPLE": processValues();                            // caseIndent
340	            case "COMPLETED": handleValue("Completed Case", 456);       // caseIndent
341	        }
342	    }
343	}
